#include <stdio.h>
#include <stdlib.h>

#define MAX_N 9

void print_board(char **board, int n) {
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            printf("%c", board[i][j]);
        }
        printf("\n");
    }
}

int is_safe(char **board, int n, int row, int col) {
    for (int i = 0; i < row; i++) {
        if (board[i][col] == 'Q') {
            return 0;
        }
    }
    for (int i = row, j = col; i >= 0 && j >= 0; i--, j--) {
        if (board[i][j] == 'Q') {
            return 0;
        }
    }
    for (int i = row, j = col; i >= 0 && j < n; i--, j++) {
        if (board[i][j] == 'Q') {
            return 0;
        }
    }
    return 1;
}

void solve_n_queens(char **board, int n, int row) {
    if (row == n) {
        print_board(board, n);
        printf("\n");
        return;
    }
    for (int col = 0; col < n; col++) {
        if (is_safe(board, n, row, col)) {
            board[row][col] = 'Q';
            solve_n_queens(board, n, row + 1);
            board[row][col] = '.';
        }
    }
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
